define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

define i32 @select_of_symmetric_selects_negative1(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c2, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

define i32 @selectSelect11(i1 %cond1, i1 %cond2, i32 %var, i32 %defaultVal) {
  %sel1 = select i1 %cond1, i32 %defaultVal, i32 %var
  %sel2 = select i1 %cond2, i32 %defaultVal, i32 %sel1
  ret i32 %sel2
}

define i32 @selectSelect11Use(i1 %cond1, i1 %cond2, i32 %var, i32 %defaultVal) {
  %sel1 = select i1 %cond1, i32 %defaultVal, i32 %var
  %sel2 = select i1 %cond2, i32 %defaultVal, i32 %sel1
  call void @use32(i32 %sel1)
  ret i32 %sel2
}

